export async function seedExercises() {
  console.log(`Seeding ${SEEDED_EXERCISES.length} exercises...`);

  // Insert in batches of 50 to avoid query limits
  const batchSize = 50;
  for (let i = 0; i < SEEDED_EXERCISES.length; i += batchSize) {
    const batch = SEEDED_EXERCISES.slice(i, i + batchSize);
    await db.insert(exercises).values(batch).onConflictDoNothing();
    console.log(`  Inserted batch ${Math.floor(i / batchSize) + 1}`);
  }

  console.log('Exercise seed complete.');
}
